def recursiveDeleteNthNode(node, n):
    if not node:
        return 1
    numIndexFromReverse = recursiveDeleteNthNode(node.next,n)
    if numIndexFromReverse==n+1:
        node.next = node.next.next
        return 0
    return 0 if numIndexFromReverse==0 else numIndexFromReverse+1






