def findIntersection(firstHead, secondHead):

    len1 = 0
    len2 = 0

    node1, node2 = firstHead, secondHead
    while(node1 or node2):
        if node1:
            len1 += 1
            node1 = node1.next
        if node2:
            len2 += 1
            node2 = node2.next

    diff = abs(len1-len2)

    if len1>len2:
        node1, node2 = firstHead, secondHead
    else:
        node2, node1 = firstHead, secondHead

    for _ in range(diff):
        node1 = node1.next

    for _ in range(min(len1,len2)):
        if node1==node2:
            return node1.val
        node1 = node1.next
        node2 = node2.next

    return -1

def oddEvenLinkedList(head):
    node, oddTail, isOddList = head,  None, True
    evenHead = head.next if head else None
    while node:
        nextNode = node.next
        if nextNode:
            node.next = nextNode.next
        if isOddList:
            oddTail = node
        isOddList = not isOddList
        node = nextNode
    if oddTail:
        oddTail.next = evenHead
    return head

import heapq

class Solution:
    def mergeKLists(self, lists: list[ListNode]) -> ListNode:
        heap = []
        # Initialize heap with the head of each list
        for i, node in enumerate(lists):
            if node:
                heapq.heappush(heap, (node.val, i, node))  # i as tiebreaker

        dummy = ListNode(0)
        tail = dummy

        while heap:
            val, i, node = heapq.heappop(heap)
            tail.next = node
            tail = tail.next
            if node.next:
                heapq.heappush(heap, (node.next.val, i, node.next))

        return dummy.next

class Solution:
    def mergeKLists(self, lists: list[ListNode]) -> ListNode:
        if not lists:
            return None
        if len(lists) == 1:
            return lists[0]

        def merge2(l1, l2):
            dummy = ListNode(0)
            tail = dummy
            while l1 and l2:
                if l1.val < l2.val:
                    tail.next = l1
                    l1 = l1.next
                else:
                    tail.next = l2
                    l2 = l2.next
                tail = tail.next
            tail.next = l1 if l1 else l2
            return dummy.next

        while len(lists) > 1:
            merged = []
            for i in range(0, len(lists), 2):
                l1 = lists[i]
                l2 = lists[i + 1] if i + 1 < len(lists) else None
                merged.append(merge2(l1, l2))
            lists = merged

        return lists[0]
